function seed() {
  const existingUsers = db.prepare('SELECT COUNT(*) as count FROM users').get();
  if (existingUsers.count === 0) {
    const insertUser = db.prepare(`INSERT INTO users (name, email, password_hash, role, csm_name) VALUES (?, ?, ?, ?, ?)`);
    for (const u of users) {
      const hash = bcrypt.hashSync(u.password, 10);
      insertUser.run(u.name, u.email, hash, u.role, u.csm_name);
    }
    console.log(`Seeded ${users.length} users`);
  }

  const existingAccounts = db.prepare('SELECT COUNT(*) as count FROM accounts').get();
  if (existingAccounts.count === 0) {
    const insertAccount = db.prepare(`
      INSERT INTO accounts (
        account_name, tenant_id, industry, mrr_tier, mrr, region, csm_lead, csm,
        closure_eta, cp, tam_assigned, billing_frequency, renewal_date, renewal_status,
        churn_status, churn_reason, renewal_comments, implementation_status, implementation_type,
        ps_engagement, ps_solutioning, account_understanding_session, new_csm_intro_done,
        csm_escalation_matrix_shared, ring_fence_meeting_initiated, meeting_planned_date,
        meeting_done, issue_mapping_sheet_updated, review_cadence_alignment,
        adoption_score, stickiness_score, rag_status, rag_reason, actions_taken,
        contraction_risk, churn_risk, grr, nps, adoption_rate, sa_status
      ) VALUES (
        ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?
      )
    `);
    for (const a of accounts) {
      insertAccount.run(
        a.account_name, a.tenant_id, a.industry, a.mrr_tier, a.mrr ?? 0,
        a.region, a.csm_lead, a.csm, a.closure_eta ?? null, a.cp ?? null,
        a.tam_assigned ?? null, a.billing_frequency ?? null, a.renewal_date ?? null,
        a.renewal_status ?? null, a.churn_status ?? null, a.churn_reason ?? null,
        a.renewal_comments ?? null, a.implementation_status ?? null, a.implementation_type ?? null,
        a.ps_engagement ?? null, a.ps_solutioning ?? null,
        a.account_understanding_session ?? null, a.new_csm_intro_done ?? null,
        a.csm_escalation_matrix_shared ?? null, a.ring_fence_meeting_initiated ?? null,
        a.meeting_planned_date ?? null, a.meeting_done ?? null,
        a.issue_mapping_sheet_updated ?? null, a.review_cadence_alignment ?? null,
        a.adoption_score ?? null, a.stickiness_score ?? null,
        a.rag_status ?? 'Green', a.rag_reason ?? null, a.actions_taken ?? null,
        a.contraction_risk ?? 'No', a.churn_risk ?? 'No',
        a.grr ?? null, a.nps ?? null, a.adoption_rate ?? null, a.sa_status ?? null
      );
    }
    console.log(`Seeded ${accounts.length} accounts`);
  } else {
    console.log('Data already seeded, skipping.');
  }
}

seed();
